const statsRaw = $input.first().json;
const stats = statsRaw.data || statsRaw;

if (!Array.isArray(stats)) {
  return [{ json: { error: 'No block stats' } }];
}

// Aggregate by block_id
const blockAgg = {};
stats.forEach(s => {
  const blockId = s.block_id;
  if (!blockId) return;
  if (!blockAgg[blockId]) {
    blockAgg[blockId] = { spend: 0, revenue: 0, clicks: 0, shows: 0, ads: new Set() };
  }
  blockAgg[blockId].spend += parseFloat(s.money) || 0;
  blockAgg[blockId].revenue += parseFloat(s.postbacks_confirmed_money) || 0;
  blockAgg[blockId].clicks += parseInt(s.clicks_count) || 0;
  blockAgg[blockId].shows += parseInt(s.shows_count) || 0;
  if (s.ad_id) blockAgg[blockId].ads.add(s.ad_id);
});

const blacklist = [];
const whitelist = [];
const yellow = [];

for (const [blockId, b] of Object.entries(blockAgg)) {
  const roi = b.spend > 0 ? ((b.revenue - b.spend) / b.spend * 100) : 0;
  const ctr = b.shows > 0 ? (b.clicks / b.shows * 100) : 0;

  const blockInfo = {
    block_id: parseInt(blockId),
    roi: Math.round(roi * 100) / 100,
    ctr: Math.round(ctr * 10000) / 10000,
    clicks: b.clicks,
    shows: b.shows,
    spend: Math.round(b.spend * 100) / 100,
    revenue: Math.round(b.revenue * 100) / 100,
    ad_count: b.ads.size
  };

  // GREEN: profitable block
  if (roi > 20 && b.clicks > 10 && ctr > 0.5) {
    blockInfo.classification = 'green';
    whitelist.push(blockInfo);
  }
  // RED: losing block
  else if ((roi < -30 && b.clicks > 20) || (ctr < 0.1 && b.shows > 500)) {
    blockInfo.classification = 'red';
    blacklist.push(blockInfo);
  }
  // YELLOW: observation
  else {
    blockInfo.classification = 'yellow';
    yellow.push(blockInfo);
  }
}

return [{
  json: {
    blacklist_blocks: blacklist.map(b => b.block_id),
    whitelist_blocks: whitelist.map(b => b.block_id),
    blacklist_details: blacklist,
    whitelist_details: whitelist,
    yellow_details: yellow,
    total_analyzed: Object.keys(blockAgg).length
  }
}];

const blockData = $('Classify Blocks').first().json;
const adsRaw = $('Fetch Active Ad Groups').first().json;
const ads = adsRaw.data || adsRaw;

// Get unique ad_group_ids
const adGroupIds = [...new Set((Array.isArray(ads) ? ads : []).map(a => a.ad_group_id).filter(Boolean))];

if (adGroupIds.length === 0) {
  return [{ json: { action: 'SKIP', reason: 'No ad groups found' } }];
}

// Prepare updates for each ad group
return adGroupIds.map(agId => ({
  json: {
    ad_group_id: agId,
    blacklist_blocks: blockData.blacklist_blocks,
    whitelist_blocks: blockData.whitelist_blocks,
    blacklist_count: blockData.blacklist_blocks.length,
    whitelist_count: blockData.whitelist_blocks.length,
    total_analyzed: blockData.total_analyzed
  }
}));

